/** This filter is documented in src/permissions-helper.php */
function duplicate_post_is_post_type_enabled( $post_type ) {
	$duplicate_post_types_enabled = get_option( 'duplicate_post_types_enabled', [ 'post', 'page' ] );
	if ( ! is_array( $duplicate_post_types_enabled ) ) {
		$duplicate_post_types_enabled = [ $duplicate_post_types_enabled ];
	}


	$duplicate_post_types_enabled = apply_filters( 'duplicate_post_enabled_post_types', $duplicate_post_types_enabled );
	return in_array( $post_type, $duplicate_post_types_enabled, true );
}

/**
 * Remove custom capabilities when deactivating the plugin.
 *
 * @return void
 */
function remove_capabilities() {
	$role = get_role( 'administrator' );

	// Bail early if the administrator role doesn't exist.
	if ( null === $role ) {
		return;
	}

	$role->remove_cap( ADS_TXT_MANAGE_CAPABILITY );
}

/**
	 * Function to refresh quotation
	 *
	 * @return json
	 */
function refreshCotation() {
		$results = $this->makeCotationOrder( SanitizeHelper::apply( $_GET['id'] ) );
		return wp_send_json(
			$results,
			200
		);
	}

/**
	 * Deletes all Site Kit post meta settings.
	 *
	 * @since 1.33.0
	 *
	 * @param string $scope Scope of the deletion ('site' or 'network').
	 */
function delete_post_meta( $scope ) {
		global $wpdb;

		$sites = array();
		if ( 'network' === $scope ) {
			$sites = get_sites(
				array(
					'fields' => 'ids',
					'number' => 9999999,
				)
			);
		} else {
			$sites[] = get_current_blog_id();
		}

		foreach ( $sites as $site_id ) {
			$prefix = $wpdb->get_blog_prefix( $site_id );

			// phpcs:ignore WordPress.DB.DirectDatabaseQuery
			$wpdb->query(
				$wpdb->prepare(
					"DELETE FROM {$prefix}postmeta WHERE `meta_key` LIKE %s", // phpcs:ignore WordPress.DB.PreparedSQL.InterpolatedNotPrepared
					static::KEY_PATTERN
				)
			);
		}
